from agent import *from models.products import *debug = Truedef process_productlist(data, context, session):    prods = data.xpath("//article[@class='areview']/following-sibling::a/@href")    for prod in prods:        url = prod.string()        session.queue(Request(url, use='curl'), process_product, dict(url=url))    nexturl = data.xpath("//td[@class='next']/a/@href").string()    if prods and nexturl:        session.queue(Request(nexturl, use='curl'), process_productlist, dict())def process_product(data, context, session):    product = Product()    product.name = data.xpath("//h2//a//text()").string()    product.ssid = context['url'].split('/')[-2]    product.url = context['url']    cat = data.xpath("(//ul[@class='infobox']//li[contains(.,'Plataforma')]//text())[2]").string()    if not(cat):        cat = data.xpath("(//ul[@class='infobox']//li[contains(.,'Probado en')]//text())[2]").string()    if cat:        product.category = 'Games|' + cat.split(',')[0].strip()    if not(cat):        product.category = 'Games'        manufacturer = data.xpath("//div[@class='boxbody']//li[contains(.,'Editor')]//a//text()")    if not manufacturer:        manufacturer = data.xpath("//div[@class='boxbody']//li[contains(.,'Desarrollador')]//a//text()")    if manufacturer:        product.manufacturer = manufacturer.string().strip()        review = Review()    review.title = data.xpath("//h1[@class='noflir']//text()").string()    review.date = data.xpath("//time/@datetime").string()    review.ssid = product.ssid    review.type = 'pro'    review.url = context['url']    authors = data.xpath("//li[@class='publishAuthor']//a")    for author in authors:        author_url = author.xpath("@href").string()        author_name = author.xpath(".//text()").string()        review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_name.strip()))    summary = data.xpath("//h2[@class='intro']//text()").string(multiple=True)    if summary:        review.properties.append(ReviewProperty(type='summary', value=summary.strip()))    excerpt = data.xpath("//div[@id='page0']//text()").string(multiple=True)    if excerpt:        review.properties.append(ReviewProperty(type='excerpt', value=excerpt.strip()))    grade = data.xpath("//div[@class='scoreSplit']//meter").first()    if grade:        grade_val = grade.xpath("@value").string()        grade_max = grade.xpath("@max").string()        review.grades.append(Grade(type='overall', value=float(grade_val), best=float(grade_max)))    pros = data.xpath("//div[@class='goodbad'][1]//text()").string(multiple=True)    if pros:        pros = pros.split('.')        for value in pros:            review.add_property(type='pros', value=value.strip())    cons = data.xpath("//div[@class='goodbad'][2]//text()").string(multiple=True)    if cons:        cons = cons.split('.')        for value in cons:            review.add_property(type='cons', value=value.strip())    if excerpt or summary:        product.reviews.append(review)        session.emit(product)def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=10000)]    session.queue(Request('https://www.gamereactor.es/analisis', use='curl'), process_productlist, dict())